class LoggingServer:
    def __init__(self, host='0.0.0.0', port=8080, log_file='application.log', secret_key=None):
        self.host = host
        self.port = port
        self.log_file = log_file
        self.secret_key = secret_key
        
        log_dir = os.path.dirname(log_file)
        if log_dir and not os.path.exists(log_dir):
            os.makedirs(log_dir, mode=0o755)
        
        if not os.path.exists(log_file):
            with open(log_file, 'w', encoding='utf-8') as f:
                f.write("# Log file created at %s\n" % datetime.utcnow().isoformat())
        
        os.chmod(log_file, 0o640)
    
    def handler_factory(self, *args, **kwargs):
        return SecureLogHandler(*args, log_file=self.log_file, secret_key=self.secret_key, **kwargs)
    
    def start(self):
        server = HTTPServer((self.host, self.port), self.handler_factory)
        print("Logging server started on %s:%d" % (self.host, self.port))
        print("Writing logs to: %s" % self.log_file)
        if self.secret_key:
            print("HMAC authentication enabled")
        try:
            server.serve_forever()
        except KeyboardInterrupt:
            print("\nShutting down server...")
            server.shutdown()


